const playShortScript = (seed: string, withRecorder: boolean): string => {
  const baseSession = createFallbackRunSession(seed);
  const session = withRecorder
    ? record(baseSession, {
        seed,
        createdAt: CREATED_AT,
        modelId: "none",
        contentRef: CONTENT_REF,
        writer: memoryWriter(seed)
      })
    : baseSession;

  session.step({ kind: "wait" });
  session.step({ kind: "wait" });
  session.step({ kind: "abort" });

  return computeStateHash(session.state);
};

type MutableRunSession = EngineLikeSession<RunAction, RunEvent> & {
  readonly replaceState: (state: GameState) => void;
};

const createFallbackRunSession = (seed: string): MutableRunSession => {
  const provider = new FallbackFloorContentProvider();
  let state = expectStartedRun(seed, provider);

  return {
    get state() {
      return state;
    },
    step: (action) => {
      const result = stepRun(state, action, provider);
      expect(result.ok, result.ok ? "" : result.error.message).toBe(true);
      if (!result.ok) {
        throw new Error(result.error.message);
      }
      state = result.state;
      return {
        state: result.state,
        events: result.events
      };
    },
    isTerminal: () => state.run.terminalStatus !== "ACTIVE",
    replaceState: (nextState) => {
      state = nextState;
    }
  };
};

const expectStartedRun = (
  seed: string,
  provider: FloorContentProvider
): GameState => {
  const started = startRun(seed, provider);
  expect(started.ok, started.ok ? "" : started.error.message).toBe(true);
  if (!started.ok) {
    throw new Error(started.error.message);
  }
  return started.state;
};

const requiredRuntime = (state: GameState) => {
  const runtime = currentFloorRuntime(state);
  expect(runtime).not.toBeNull();
  if (runtime === null) {
    throw new Error("missing run floor runtime");
  }
  return runtime;
};

const withPlayerPosition = (
  state: GameState,
  position: Position
): GameState => ({
  ...state,
  player: {
    ...state.player,
    position
  }
});

const memoryWriter = (seed: string) => {
  const runId = traceRunId(seed, CREATED_AT);
  return createFileTraceWriter({
    runId,
    fs: new MemoryTraceFs()
  });
};

const readTraceLines = (fs: MemoryTraceFs, runId: string): readonly string[] =>
  fs.read(`runs/${runId}/trace.ndjson`).trimEnd().split("\n");

const expectHeader = (line: string | undefined): TraceHeader => {
  expect(line).toBeDefined();
  const parsed = JSON.parse(line ?? "null") as unknown;
  expect(isRecord(parsed)).toBe(true);
  if (!isRecord(parsed) || parsed.recordType !== "header") {
    throw new Error("missing trace header");
  }
  return parsed as TraceHeader;
};

const expectTurnLine = (
  line: string | undefined
): TraceTurnLine<RunAction, RunEvent> => {
  expect(line).toBeDefined();
  const parsed = JSON.parse(line ?? "null") as unknown;
  expect(isRecord(parsed)).toBe(true);
  if (!isRecord(parsed)) {
    throw new Error("missing trace turn line");
  }
  expect(typeof parsed.turn).toBe("number");
  expect(isRecord(parsed.action)).toBe(true);
  expect(Array.isArray(parsed.events)).toBe(true);
  expect(typeof parsed.stateHash).toBe("string");
  return parsed as TraceTurnLine<RunAction, RunEvent>;
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === "object" && !Array.isArray(value);

class MemoryTraceFs implements TraceFsAdapter {
  readonly dirs: string[] = [];
  readonly files = new Map<string, string>();

  makeDir(path: string): void {
    this.dirs.push(path);
  }

});

const IdStateSchema = z.strictObject({
  entityCounters: EntityIdCountersSchema,
});

export const GameStateSchema = z
  .strictObject({
    version: VersionStampSchema,
    run: RunMetaSchema,
    floor: FloorStateSchema,
    player: PlayerStateSchema,
    entities: EntityMapSchema,
    quests: QuestStateSchema,
    log: z.array(LogEventSchema),
    rng: RngStateSchema,
    ids: IdStateSchema,
  })
  .superRefine((state, ctx) => {
    if (state.run.depth !== state.floor.depth) {
      ctx.addIssue({
        code: "custom",
        path: ["floor", "depth"],
        message: "floor depth must match run depth",
      });
    }

    if (state.run.band !== state.floor.band) {
      ctx.addIssue({
        code: "custom",
        path: ["floor", "band"],
        message: "floor band must match run band",
      });
    }

    if (state.rng.rootSeed !== state.run.seed) {
      ctx.addIssue({
        code: "custom",
        path: ["rng", "rootSeed"],
        message: "rng root seed must match run seed",
      });
    }
  });

export const serialize = (state: GameState): string => {
  const parsed = GameStateSchema.parse(state);
  return stableStringify(parsed);
};

export const deserialize = (serialized: string): GameState => {
  let parsedJson: unknown;

  try {
    parsedJson = JSON.parse(serialized);
  } catch (error) {
    throw new Error(
      `Invalid GameState JSON: ${
        error instanceof Error ? error.message : String(error)
      }`,
    );
  }

  const result = GameStateSchema.safeParse(parsedJson);
  if (!result.success) {
    throw new Error(`Invalid GameState: ${formatIssues(result.error.issues)}`);
  }

  return result.data as unknown as GameState;
};

const expectedBandFor = (
  depth: number,
  ctx: z.RefinementCtx,
  path: (string | number)[],
): string | null => {
  try {
    return depthBandForDepth(depth);
  } catch (error) {
    ctx.addIssue({
      code: "custom",
      path,
      message: error instanceof Error ? error.message : String(error),
    });
    return null;
  }
};

const stableStringify = (value: unknown): string => {
  const serialized = JSON.stringify(sortObjectKeys(value));

  if (serialized === undefined) {
    throw new Error("GameState serialization produced no JSON");
  }

  return serialized;
};

const sortObjectKeys = (value: unknown): unknown => {
  if (Array.isArray(value)) {
    return value.map((item) => sortObjectKeys(item));
  }

  if (value !== null && typeof value === "object") {
    const sorted: Record<string, unknown> = {};
    const objectValue = value as Record<string, unknown>;

    for (const key of Object.keys(objectValue).sort()) {
      sorted[key] = sortObjectKeys(objectValue[key]);
    }

    return sorted;
  }

  return value;
};

const formatIssues = (issues: readonly z.core.$ZodIssue[]): string =>
  issues
    .map((issue) => {
      const path = issue.path.length > 0 ? issue.path.join(".") : "<root>";
      return `${path}: ${issue.message}`;
    })
    .join("; ");

import { appendFileSync, mkdirSync, writeFileSync } from "node:fs";

import { ENGINE_VERSION, PROTOCOL_VERSION } from "../../schemas/protocol.js";
import type { EngineLogEvent, GameState } from "../../engine/state/index.js";
import { computeStateHash } from "./hash.js";

export type TraceContentRef = {
  readonly providerId: string;
  readonly packVersion: string;
};

export type TraceHeader = {
  readonly recordType: "header";
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
};

export type TraceTurnLine<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly turn: number;
  readonly action: Action;
  readonly events: readonly Event[];
  readonly stateHash: string;
};

export type EngineLikeStepResult<
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly events: readonly Event[];
};

export type EngineLikeSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly getAvailableActions?: () => readonly Action[];
  readonly step: (action: Action) => EngineLikeStepResult<Event>;
  readonly isTerminal?: () => boolean;
};

export type RecordedSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = EngineLikeSession<Action, Event> & {
  readonly trace: TraceRecorder<Action, Event>;
};

export type TraceRecorderOptions = {
  readonly seed: string;
  readonly createdAt: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
};

export type TraceRecorder<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly header: TraceHeader;
  readonly path: string;
  readonly recordTurn: (
    action: Action,
    result: EngineLikeStepResult<Event>
  ) => TraceTurnLine<Action, Event>;
};

export type TraceWriter = {
  readonly path: string;
  readonly writeHeader: (header: TraceHeader) => void;
  readonly appendTurn: <Action, Event extends EngineLogEvent>(
    line: TraceTurnLine<Action, Event>
  ) => void;
};

export type TraceFsAdapter = {
  readonly makeDir: (path: string) => void;
  readonly writeNewFile: (path: string, contents: string) => void;
  readonly appendFile: (path: string, contents: string) => void;
};

export type FileTraceWriterOptions = {
  readonly runId: string;
  readonly rootDir?: string;
  readonly fs?: TraceFsAdapter;
};

export const createTraceRecorder = <
  Action,
  Event extends EngineLogEvent = EngineLogEvent
>(
  options: TraceRecorderOptions
): TraceRecorder<Action, Event> => {
  const runId = options.runId ?? traceRunId(options.seed, options.createdAt);
  const writer = options.writer ?? createFileTraceWriter({ runId });
  const header: TraceHeader = {
    recordType: "header",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    modelId: options.modelId,
    contentRef: options.contentRef,
    seed: options.seed,
    createdAt: options.createdAt,
    runId
  };

  writer.writeHeader(header);

  return {
    header,
    path: writer.path,
    recordTurn: (action, result) => {
      // Trace turn numbers use the recorder's post-step state convention.
      const line: TraceTurnLine<Action, Event> = {
        turn: result.state.run.turn,
        action,
        events: result.events,
        stateHash: computeStateHash(result.state)
      };
      writer.appendTurn(line);
      return line;
    }
  };
};

export const record = <Action, Event extends EngineLogEvent = EngineLogEvent>(
  session: EngineLikeSession<Action, Event>,
  options: TraceRecorderOptions
): RecordedSession<Action, Event> => {
  const trace = createTraceRecorder<Action, Event>(options);

  return {
    get state() {
      return session.state;
    },
    getAvailableActions: session.getAvailableActions?.bind(session),
    isTerminal: session.isTerminal?.bind(session),
    step: (action) => {
      const result = session.step(action);
      trace.recordTurn(action, result);
      return result;
    },
    trace
  };
};

export const createFileTraceWriter = (
  options: FileTraceWriterOptions
): TraceWriter => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const dir = `${rootDir}/${options.runId}`;
  const path = `${dir}/trace.ndjson`;
  const fs = options.fs ?? nodeTraceFsAdapter;

  return {
    path,
    writeHeader: (header) => {
      fs.makeDir(dir);
      fs.writeNewFile(path, `${JSON.stringify(header)}\n`);
    },
    appendTurn: (line) => {
      fs.appendFile(path, `${JSON.stringify(line)}\n`);
    }
  };
};

export const traceRunId = (seed: string, createdAt: string): string =>
  `run-${runIdComponent(seed)}-${runIdComponent(createdAt)}`;

const runIdComponent = (value: string): string => {
  const component = value
    .replace(/[^A-Za-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");

  if (component.length === 0) {
    return "blank";
  }

  return component.slice(0, 80);
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

const nodeTraceFsAdapter: TraceFsAdapter = {
  makeDir: (path) => {
    mkdirSync(path, { recursive: true });
  },
  writeNewFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8", flag: "wx" });
  },
  appendFile: (path, contents) => {
    appendFileSync(path, contents, { encoding: "utf8" });
  }
};

import { serialize, type GameState } from "../../engine/state/index.js";

const FNV_OFFSET_BASIS = 0x811c9dc5;
const FNV_PRIME = 0x01000193;

export const computeStateHash = (state: GameState): string =>
  hashSerializedState(serialize(state));

export const hashSerializedState = (serialized: string): string => {
  let hash = FNV_OFFSET_BASIS;

  for (let index = 0; index < serialized.length; index += 1) {
    hash ^= serialized.charCodeAt(index);
    hash = Math.imul(hash, FNV_PRIME) >>> 0;
  }

  return hash.toString(16).padStart(8, "0");
};

